compliant:
public void DoTheThing(string str, int i, List<string> strings)
{
    Console.WriteLine(str); // Use parameter first
    str = i.ToString(); // Compliant: parameter used before reassignment

    foreach (var s in strings)
    {
        Console.WriteLine(s); // Compliant: use value from collection
    }
}

